import{_ as i,o as l,c as o,a0 as t,j as a,t as r}from"./chunks/framework.CSGB4SNl.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"vue/vue-day01.md","filePath":"vue/vue-day01.md"}'),s={name:"vue/vue-day01.md"};function n(d,e,u,v,h,c){return l(),o("div",null,[e[0]||(e[0]=t('<h4 id="说说你对vue的理解" tabindex="-1">说说你对vue的理解 <a class="header-anchor" href="#说说你对vue的理解" aria-label="Permalink to &quot;说说你对vue的理解&quot;">​</a></h4><ol><li>数据驱动mvvm，模型层负责处理业务逻辑和服务端交互，视图-负责将模型层处理的业务数据展示成ui界面，模型视图层负责将两者连接起来</li><li>组件化：将图形和非图形的逻辑抽象为一个.vue结尾的文件</li><li>指令系统：带有v-开头的指令当里面的属性值改变时其产生的连带影响会直接或间接作用于dom：如条件渲染v-if，列表渲染v-for、属性绑定v-bind、数据绑定v-model、事件绑定v-on</li><li>vue基本不操作dom节点，通过双向绑定使dom和视图节点，通过操作控制视图节点的变量去控制dom的属性，这是虚拟dom</li><li>与react区别：推双向数据流，vue使用可变数据、父子通信不同：vue即可以通过事件也可以回调函数，diff算法不同：vue双向指针是变比对变更新dom</li></ol><h4 id="spa单页应用优缺点" tabindex="-1">SPA单页应用优缺点 <a class="header-anchor" href="#spa单页应用优缺点" aria-label="Permalink to &quot;SPA单页应用优缺点&quot;">​</a></h4><ol><li>单页应用就是根据用户的响应动态改变里面的内容，通过单个页面加载而检索并适当加载需要的资源添加到页面，在任何时间点都不会重新加载也不会将控制转移到其它页面，就是结构不变变的是内容，常见前端框架都是SPA</li><li>MPA：每个页面都是一个主页面，跳转其它页面都会更新当前页面的资源html、css、js等，单页应用是局部刷新，多页数据传递要通过url、cookie、localStorage</li><li>要实现单页应用的话，监听地址栏中的hash变化来驱动页面变化，用pushsate记录浏览器历史驱动页面发送变化</li></ol><h4 id="v-show和v-if有什么区别-使用场景分别是什么" tabindex="-1">v-show和v-if有什么区别？使用场景分别是什么？ <a class="header-anchor" href="#v-show和v-if有什么区别-使用场景分别是什么" aria-label="Permalink to &quot;v-show和v-if有什么区别？使用场景分别是什么？&quot;">​</a></h4><ol><li>都是控制页面上的元素是否显示，但是show是通过控制css的display：none来控制，编译过程也包括组件的卸载需要卸载组件中的监听器、子组件、相关逻辑等，就会触发组件的生命周期，性能消耗方面if会有较大的切换开销、show只是初始时的渲染消耗</li><li>解析流程：将所需tem模板中的元素转化成一个js对象，然后拼接render等，被调用后创建一个虚拟VNODE节点最后通过虚拟DOM算法转化成真实DOM-通过表达式的值来决定是否生成，show不管初始条件如何都会渲染，过程是有transition执行transition，没有则设置display</li><li>频繁切换选show，较少切换选if</li></ol><h4 id="vue实例挂载的过程" tabindex="-1">VUE实例挂载的过程 <a class="header-anchor" href="#vue实例挂载的过程" aria-label="Permalink to &quot;VUE实例挂载的过程&quot;">​</a></h4>',7)),a("ol",null,[a("li",null,"先创建一个vue对象，准备里面的响应式数据和相关方法如函数、计算属性等配置，接下来是模板编译，找到要挂载的地方如#app，读取里面的所有html元素信息，找到如"+r()+"这类的模板语法，然后将其转化成render方法，render方法里面就是来创建虚拟DOM往里面添加元素-对应数据，最后执行render函数渲染成真实DOM",1)])])}const _=i(s,[["render",n]]);export{f as __pageData,_ as default};
